const payload = {
  source: $json.source,
  version: $json.version,
  generated_at: $json.generated_at,
  batch_id: $json.batch_id,
  data: [
    {
      id: 'openai-gpt-4o',
      title: 'OpenAI GPT-4o',
      summary: 'Multimodal foundation model for text, image, and voice workflows.',
      url: 'https://openai.com',
      source: 'openai',
      category: 'foundation-model',
      recommended_action: 'track',
      published_date: '2026-04-10T00:00:00.000Z',
      final_score: 9.2,
      lifecycle_status: 'hot',
      value_stream: ['customer-support', 'internal-productivity'],
      work_phase: ['ideation', 'delivery', 'operations'],
      tool_type: ['foundation'],
      service_model: ['cloud'],
      pricing_model: ['subscription', 'usage-based'],
      integrability: ['api'],
      compliance: ['soc2'],
      validation_level: ['production-used'],
      target_use: ['general-assistant', 'workflow-automation'],
      explainability: ['medium'],
      language: ['english', 'multilingual'],
      tool_maturity: ['mature'],
      vendor_maturity: ['established'],
      discontinued: false,
      metadata: {
        vendor: 'OpenAI',
        tags: ['llm', 'multimodal', 'enterprise'],
        last_seen_at: $json.generated_at,
        collector: 'n8n'
      }
    }
  ]
};

const rawBody = JSON.stringify(payload);
const timestamp = Math.floor(Date.now() / 1000).toString();

return [{
  json: {
    payload,
    rawBody,
    timestamp
  }
}];

const crypto = require('crypto');
const secret = $env.RADAR_INGEST_SECRET || 'replace-me';
const rawBody = $json.rawBody;
const signature = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
return [{
  json: {
    payload: $json.payload,
    rawBody,
    timestamp: $json.timestamp,
    signature
  }
}];
